+            cmd_vel_msg.linear.x = 0.0;
+            cmd_vel_msg.angular.z = 0.0;
+            running_ = false;
+        }
+    }
+
+    // Publish the velocity command
+    cmd_vel_pub_->publish(cmd_vel_msg);
+    return running_;
+}
