+            if (searchRadius > 10)
+                LOG_CRITICAL("Cannot find closest node within 10m. This is not ok.")
+            for (int dx = -searchRadius; dx <= searchRadius; ++dx)
+            {
+                for (int dy = -searchRadius; dy <= searchRadius; ++dy)
